sql:
SELECT title
FROM events
ORDER BY event_id;

SELECT event_id, COUNT(participant_id) AS total_registered_participants
FROM event_participants
GROUP BY event_id;

SELECT event_id, participant_id
FROM event_participants
WHERE event_participant_id = 0;

SELECT COUNT(*) 
FROM event_documents 
WHERE document_type = 'abstract' AND is_active = 1;
